const AWS = require('aws-sdk');
const { exec } = require('child_process');

exports.handler = async (event) => {
    const s3 = new AWS.S3();
    const bucketName = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    const outputFormat = event.Records[0].eventMetadata.outputFormat;

    if (!outputFormat) {
        return {
            statusCode: 400,
            body: JSON.stringify({ message: 'Output format is required' })
        };
    }

    const params = {
        Bucket: bucketName,
        Key: key
    };

    try {
        const data = await s3.getObject(params).promise();
        const tempFilePath = `/tmp/${key}`;
        const outputFilePath = `/tmp/output.${outputFormat}`;

        // Write the image to a temporary file
        require('fs').writeFileSync(tempFilePath, data.Body);

        // Execute ImageMagick convert command
        exec(`convert ${tempFilePath} ${outputFilePath}`, (error, stdout, stderr) => {
            if (error) {
                console.error(`Error executing ImageMagick: ${stderr}`);
                return {
                    statusCode: 500,
                    body: JSON.stringify({ message: 'Failed to convert image' })
                };
            }

            // Upload the converted image back to S3
            const uploadParams = {
                Bucket: bucketName,
                Key: `converted/${key.split('.').slice(0, -1).join('.')}.${outputFormat}`,
                Body: require('fs').readFileSync(outputFilePath),
                ContentType: `image/${outputFormat}`
            };

            s3.upload(uploadParams, (uploadError, uploadData) => {
                if (uploadError) {
                    console.error(`Error uploading converted image: ${uploadError}`);
                    return {
                        statusCode: 500,
                        body: JSON.stringify({ message: 'Failed to upload converted image' })
                    };
                }

                return {
                    statusCode: 200,
                    body: JSON.stringify({ message: 'Image converted and uploaded successfully', url: uploadData.Location })
                };
            });
        });
    } catch (error) {
        console.error(`Error retrieving image from S3: ${error}`);
        return {
            statusCode: 500,
            body: JSON.stringify({ message: 'Failed to retrieve image' })
        };
    }
};